// parseAndExecuteCommand parses a raw command string and executes it
func (s *Server) parseAndExecuteCommand(sender *Client, rawCommand string) {
	parts := strings.Fields(rawCommand) // Splits by whitespace
	if len(parts) == 0 {
		sender.SendMessage(Message{
			Type:    CommandResponseType,
			Sender:  "Server",
			Content: "Invalid command format.",
			Success: false,
		})
		return
	}

	cmdName := strings.ToLower(strings.TrimPrefix(parts[0], "/"))
	args := []string{}
	if len(parts) > 1 {
		args = parts[1:]
	}

	cmd, found := s.commands[cmdName]
	if !found {
		sender.SendMessage(Message{
			Type:    CommandResponseType,
			Sender:  "Server",
			Content: fmt.Sprintf("Unknown command: %s", cmdName),
			Success: false,
		})
		return
	}

	// Check roles
	if len(cmd.RequiredRoles) > 0 {
		authorized := false
		for _, requiredRole := range cmd.RequiredRoles {
			if sender.HasRole(requiredRole) {
				authorized = true
				break
			}
		}
		if !authorized {
			sender.SendMessage(Message{
				Type:    CommandResponseType,
				Sender:  "Server",
				Content: fmt.Sprintf("Permission denied: You need one of these roles: %s", strings.Join(cmd.RequiredRoles, ", ")),
				Success: false,
			})
			return
		}
	}

	// Execute command
	err := cmd.Handler(s, sender, args)
	if err != nil {
		sender.SendMessage(Message{
			Type:    CommandResponseType,
			Sender:  "Server",
			Content: fmt.Sprintf("Command failed: %s", err.Error()),
			Success: false,
			Error:   err.Error(),
		})
	} else {
		// Handler functions typically send their own success messages.
		// If a handler doesn't send a specific message, a generic success can be sent.
		// For this example, handlers are expected to send their own messages.
	}
}

